previewCss:
.darma-loader-darma-custom-672 {color: var(--loader-color, #ffffff);
  --loader-secondary-color: var(--loader-secondary-color, #fed59f);
  --loader-bg: var(--loader-bg, #f8fafc);

  width: 100px;
  height: 80px;
  position: relative;
  display: flex;
  justify-items: center;
  align-items: center;
}
.darma-loader-darma-custom-672 .darma-loader-darma-custom-672__cup {
  position: absolute;
  width: 25px;
  height: 18px;
  background-color: currentColor;
  border: 1px solid #2e2e2e;
  z-index: 1;
  border-radius: 2px 2px 10px 10px;
  animation: darma-loader-darma-custom-672-expansion 6s infinite ease-in-out;
  transform-origin: center;
}

.darma-loader-darma-custom-672__cup::after {
  content: "";
  position: absolute;
  top: -2px;
  width: calc(100% - 2px);
  height: 2px;
  background: #fed59fca;
  border: 1px solid #2e2e2ebe;
  border-radius: 50%;
}
.darma-loader-darma-custom-672__cup::before {
  content: "";
  position: absolute;
  top: 15px;
  width: calc(100% - 2px);
  height: 4px;
  background: #ffffff00;
  border: 1px solid #2e2e2e;
  border-top: none;
  border-radius: 50%;
  z-index: 0;
}

.darma-loader-darma-custom-672 .darma-loader-darma-custom-672__cup .darma-loader-darma-custom-672__cup-handle {
  position: absolute;
  width: 5px;
  height: 10px;
  background-color: currentColor;
  border: 1px solid #2e2e2e;
  right: -5px;
  top: 2px;
  border-radius: 2px 10px 20px 2px;
}

.darma-loader-darma-custom-672 .darma-loader-darma-custom-672__cup .darma-loader-darma-custom-672__smoke {
  position: absolute;
  bottom: 100%;
  left: 50%;
  width: 15px;
  height: 25px;
  background: rgba(107, 102, 102, 0.433);
  border-radius: 50%;
  transform: translateX(-50%);
  animation: darma-loader-darma-custom-672-rise 6s infinite ease-in-out;
  filter: blur(8px);
}

.darma-loader-darma-custom-672 .darma-loader-darma-custom-672__cup .darma-loader-darma-custom-672__smoke.darma-loader-darma-custom-672__one {
  animation-delay: 0s;
}
.darma-loader-darma-custom-672 .darma-loader-darma-custom-672__cup .darma-loader-darma-custom-672__smoke.darma-loader-darma-custom-672__two {
  animation-delay: 1s;
}
.darma-loader-darma-custom-672 .darma-loader-darma-custom-672__cup .darma-loader-darma-custom-672__smoke.darma-loader-darma-custom-672__three {
  animation-delay: 2s;
}

.darma-loader-darma-custom-672 .darma-loader-darma-custom-672__load {
  position: absolute;
  font-size: 10px;
  opacity: 0.7;
  top: 45%;
  left: 50%;
  transform: translateX(-50%);
  z-index: 0;
}

@keyframes darma-loader-darma-custom-672-expansion {
  0% {
    width: 25px;
    transform: translateX(0);
  }
  40% {
    width: 100%;
    transform: translateX(0);
  }
  80% {
    width: 25px;
    transform: translateX(64px);
  }
  90% {
    width: 100%;
    transform: translateX(0);
  }
  100% {
    width: 25px;
    transform: translateX(0);
  }
}

@keyframes darma-loader-darma-custom-672-rise {
  0% {
    transform: translate(-50%, 0) scale(0.4);
    opacity: 0;
  }
  30% {
    opacity: 0.7;
  }
  60% {
    opacity: 0.4;
  }
  100% {
    transform: translate(-50%, -120px) scale(1);
    opacity: 0;
  }
}

